{
  "name": "Supplemental Nutrition Assistance Program (SNAP)",
  "eligibility": {
    "age": 60,
    "income_limits": "For households with a member 60+ or disabled in Iowa (Oct 1, 2025 - Sep 30, 2026): Gross monthly income limit at 160% FPL - 1 person: $2086, 2: $2820, 3: $3553, 4: $4286, 5: $5020, 6: $5753, 7: $6486, +$732 each additional. If over gross limit, qualify via net income (100% FPL after deductions) and asset tests. Seniors 60+ get higher medical deduction (over $35/month), shelter deduction, and no gross income test if all elderly/disabled[1][2][6].",
    "asset_limits": "Households where all members are 60+ or disabled often have no asset limits (categorical eligibility in Iowa). Standard resources include countable assets like cash; exempt: home, most retirement savings, one vehicle[1][2][4].",
    "other_requirements": ["Iowa resident", "U.S. citizen or qualified non-citizen", "SSI recipients often categorically eligible", "New work requirements (80 hours/month work/volunteer/training) may apply to ages 55-64 without dependents per 2025 changes, but 60+ typically exempt or fewer requirements[5][6][7]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly benefits loaded on EBT card for food purchases at authorized stores. Max for 1-person: ~$291, 2-person: ~$535 (2026); actual amount based on net income, household size, deductions (e.g., $100 more net income = ~$30 less benefits). Most seniors receive less than max[1].",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: Iowa state portal (via hhs.iowa.gov)", "Phone: Local Department of Social Services or state SNAP hotline", "In-person/mail: Local Department of Social Services offices", "Telephone interviews often available for elderly[1][7]"],
    "processing_time": "Not specified in sources; typically 30 days standard, expedited for urgent cases[1]",
    "waitlist": null,
    "forms": ["SNAP application via Iowa DHS portal or local office (no specific form number listed)"],
    "documents": ["ID/proof of residency", "Proof of income (Social Security, pension, etc.)", "Proof of expenses (rent, utilities, medical over $35/month, bank statements)[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered locally via Department of Social Services offices; no major differences noted, but apply at local office. Possible variation in wait times/interviews[1][7]",
    "offices_or_providers": ["Local Iowa Department of Social Services offices"]
  },
  "official_source": "https://hhs.iowa.gov/assistance-programs/food-assistance/snap",
  "gotchas": ["Iowa expanded eligibility to 160% FPL gross (higher than federal 130%), but must meet net/asset if over gross; seniors miss higher deductions for medical/shelter costs; new 2025 work rules impact 55-64; include all who buy/prepare food in household; SSI auto-eligible but verify[1][2][4][5][6]", "Own home/retirement savings often don't count as assets"],
  "data_shape_notes": "Benefits scale by household size and net income with special elderly deductions; Iowa has broader gross income test (160% FPL) and categorical eligibility for SSI/elderly/disabled households; statewide but local admin"
}

{
  "name": "Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "At or below 200% of Federal Poverty Guidelines. Example from New Opportunities Inc. (may vary slightly by agency/year): 1: $31,300; 2: $42,300; 3: $53,300; 4: $64,300; 5: $75,300; 6: $86,300; 7: $97,300; 8: $108,300 (add $11,000 per additional member). Alliant Energy example: 1: $24,120 annual/$6,030 three-month; 2: $32,480/$8,120; 3: $40,840/$10,210; 4: $12,300 three-month (annual not fully listed). Must often qualify/receive LIHEAP (income-tested at ~175% FPL in some policies).[1][2][5][6][8]",
    "asset_limits": "No asset limits mentioned across sources.",
    "other_requirements": ["Typically requires qualifying for or receiving LIHEAP (Heating Assistance) in the last 12 months.", "Proof of legal U.S. status.", "Homes selected from priority list based on prior LIHEAP applicants, energy usage, and county lists.", "Owners and renters both qualify.", "Particularly prioritizes elderly, disabled, children, but no strict age cutoff."][2][3][4][6][7]
  },
  "benefits": {
    "type": "service",
    "value": "Energy efficiency improvements via professional energy audit, including insulation (attic, sidewall, crawl space), sealing cracks/holes, furnace tune/clean/repair/replacement, water heater repair/replacement, smoke/CO detectors, LED bulbs, blower door testing, health/safety fixes. No fixed dollar amount; varies by audit, funding, home needs. ~2,000 homes statewide/year; e.g., 50 homes/year in SE Iowa.[1][2][6][7]",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Contact local Community Action Agency or outreach office in your county (year-round).", "Apply via LIHEAP application (online Nov-Apr; phone/mail/in-person other times).", "Phone: State customer service 515-281-3861.", "Locate agency: https://hhs.iowa.gov/assistance-programs/housing-rent-assistance/weatherization-assistance (Intake List).", "Examples: CA Southeast Iowa (caofseia.org), New Opportunities (newopp.org), Upper Des Moines (udmo.com), Mid-Sioux (midsioux.org)."][1][3][4][6][7],
    "processing_time": "Agency schedules appointment; income check then placed on waiting list. No fixed timeline given.",
    "waitlist": "Yes, statewide ~80,000 eligible applicants vs. 2,000 served/year; priority list by county, prior LIHEAP, energy usage. Long waits common; may not receive services despite eligibility due to list position.[1][2][4]",
    "forms": ["LIHEAP Application (English/Spanish; doubles as Weatherization app). No specific WAP form number listed."][3][6],
    "documents": ["Proof of identity/SSN for all household members (SS cards, unexpired IA DL/REAL ID, passport).", "Gas/electric/water utility bills.", "Proof of gross income (past 30 days or year; all adults)."][3][5]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered via local Community Action Agencies by county; some agencies list specific counties (e.g., Mid-Sioux: Lyon, Sioux, Plymouth, Cherokee, Ida).",
    "regional_variations": "Services/funding vary by area, agency, funding availability, cost limits; different homes served/year (e.g., 50 in SE Iowa); priority lists per county; different providers.[1][3][6]",
    "offices_or_providers": ["Local Community Action Agencies (county-specific; find via state site or 515-281-3861). Examples: Community Action of Southeast Iowa, New Opportunities Inc., Upper Des Moines Opportunity, Mid-Sioux Opportunity."][1][2][3][6][7]
  },
  "official_source": "https://hhs.iowa.gov/assistance-programs/housing-rent-assistance/weatherization-assistance",
  "gotchas": ["Applying for LIHEAP automatically applies you for Weatherization, but eligibility ≠ services due to funding limits/waitlists.", "Homes pulled from prior-year LIHEAP priority lists; high energy use prioritized.", "Long waits (thousands eligible, few served); reapply yearly if needed.", "Must contact LOCAL agency, not state directly for most steps.", "Varying income tables by agency; confirm with local provider.", "No services guaranteed even if eligible."][1][2][4],
  "data_shape_notes": "Linked to LIHEAP grantees/priority lists by county; severe funding shortage (80k eligible vs 2k served); administered via ~local agencies with regional funding/service variations; no age cutoff but targets elderly/disabled/kids."
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually and by household size; for example, in prior years for a family of 1 it was approximately $14,850 (2020 estimate). Contact provider for current 2026 table.[1][2][7]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "Iowa resident", "Low employment prospects (e.g., due to lack of experience, outdated skills, or long-term unemployment)", "Priority: Veterans and qualified spouses first, then individuals over 65, with disabilities, low literacy, limited English proficiency, rural residents, homeless/at risk, low employment prospects, or prior American Job Center users"][1][2][3][5]
  },
  "benefits": {
    "type": "employment",
    "value": "Paid on-the-job training (average 20 hours/week) at non-profit/public sites (e.g., schools, hospitals, senior centers); wage at highest of federal ($7.25/hour), state, or local minimum wage; fringe benefits include annual physical exam, workers' compensation, federal holiday pay, sick leave (no unemployment insurance or retirement contributions); skills training to bridge to unsubsidized jobs; access to American Job Centers.[1][2][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Visit local IowaWORKS office (statewide network)",
      "Email Bethany Ellingson, SCSEP Program Coordinator, at Bethany.Ellingson@iwd.iowa.gov",
      "Contact Iowa Workforce Development (IWD) via workforce.iowa.gov/jobs/worker-programs/scsep"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": "Not specified; funding via sub-grantees may create regional limits.",
    "forms": ["No specific form name/number listed; general SCSEP application process via provider"],
    "documents": ["Proof of age, income, unemployment status, residency (e.g., ID, pay stubs, tax returns inferred from standard practices; confirm with provider)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available across Iowa via Iowa Department on Aging/Iowa Workforce Development oversight and sub-grantees.",
    "regional_variations": "Administered through local IowaWORKS offices and sub-grantee networks; potential differences in providers, availability, wait times by region (e.g., National Able Network serves Iowa among other states).[3][4][7]",
    "offices_or_providers": ["IowaWORKS offices statewide", "Iowa Department on Aging", "Potential sub-grantees like National Able Network or CWI Works (multi-state)"]
  },
  "official_source": "https://workforce.iowa.gov/jobs/worker-programs/scsep",
  "gotchas": [
    "Must be unemployed at enrollment; program is temporary training bridge, not permanent job.",
    "Priority tiers limit access for non-priority applicants.",
    "Income at exactly 125% FPL; verify current levels as they update yearly.",
    "No retirement contributions or unemployment insurance during participation.",
    "Oversight by Iowa Workforce Development with sub-grantees; services may shift with grants (e.g., new sub-grantee sought for 2025-2026)."
  ],
  "data_shape_notes": "Income at 125% FPL (varies by household size, annual update); priority enrollment tiers; statewide but via regional IowaWORKS offices and sub-grantees; no fixed asset test."
}

{
  "name": "Iowa Legal Aid for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "Up to 125% of the federal poverty level (exceptions up to 200% in some cases; special grants for higher incomes for seniors on specific issues). Exact dollar amounts vary by household size and year; contact for current table as 2026 figures not specified in sources[2][6][9].",
    "asset_limits": "No specific asset limits mentioned for Iowa Legal Aid for Seniors; means testing prohibited—services not denied based on finances for those 60+[1]. (Note: Medicaid-related programs they assist with have limits like $2,000 for singles[3][5]).",
    "other_requirements": ["Iowa resident", "Low-income or priority needs (rural, economic/social need, disabilities, limited English, Alzheimer's, at risk of institutionalization/homelessness/guardianship)[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal assistance including advice, counseling, representation on elder law issues (e.g., housing, public benefits, abuse prevention, Medicaid planning, guardianships, benefits screening via tools like BenefitsCheckUp)[1][6][7][8][10]. No fixed dollar amounts or hours specified.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 1-800-532-1503 or 800-992-8161 (seniors hotline)[7][8]", "Online: iowalegalaid.org (apply to find out if qualify)[2][7]", "In-person: Local offices statewide (e.g., Johnson County reference)[6]"],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["Online application via iowalegalaid.org; no specific form name/number listed[2]"],
    "documents": ["Proof of income, age, residency; prepare details on legal issue (not explicitly listed, but standard for legal aid intake)[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Accessible in each county throughout Iowa[1]",
    "regional_variations": "Local level consideration for priorities and coordination with existing services; no specific wait time or provider differences noted[1]",
    "offices_or_providers": ["Iowa Legal Aid offices statewide; coordinates with Legal Services Corporation projects[1][6]"]
  },
  "official_source": "https://iowalegalaid.org",
  "gotchas": ["Not automatic—must apply to confirm qualification even if 60+; income exceptions not guaranteed[2]", "Priority for greatest need (e.g., frail, rural, at risk); others may be waitlisted or referred[1]", "Separate from Medicaid Elderly Waiver (which has strict asset/income rules they can assist with)[3][4]", "Means testing prohibited, but funding guidelines influence help[1][6]"],
  "data_shape_notes": "No strict asset test but income up to 125% FPL with senior priority; statewide with local targeting; services via grants for elders beyond standard limits"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to any resident regardless of financial status[1][6]",
    "asset_limits": "No asset limits; no financial tests apply[1][6]",
    "other_requirements": ["Must be a resident or tenant of a long-term care facility in Iowa, including nursing homes, assisted living programs, residential care facilities, or elder group homes (per Iowa Code chapter 135C)[1][5][6]", "Also serves those enrolled in Iowa’s Home and Community-Based Services (HCBS) waiver programs (AIDS/HIV, Brain Injury, Children’s Mental Health, Elderly, Health and Disability, Intellectual Disability, Physical Disability), and Medicaid managed care members[6]", "Exclusions for certain assisted living/residential care: acute stage of alcoholism/drug addiction/uncontrolled mental illness; under age 18; requires more than part-time/intermittent health-related care; unmanageable incontinence despite program; behavior placing others at risk[1][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including investigating complaints about conditions/treatment, resolving problems, educating on resident rights, clarifying regulations/policies/managed care processes, assistance with involuntary discharge/facility closure, information on resident/family councils, self-advocacy support, and substitute decision makers (e.g., power of attorney, guardian); no fixed dollar amounts or hours—response based on need, provided by paid staff and certified volunteers[1][3][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Call statewide hotline at 1-800-532-3213 (access code 878277# for prompts)[7]", "Contact Local Long-Term Care Ombudsman (posted in every facility)[5]", "Visit official website: https://hhs.iowa.gov/health-prevention/aging-services/ltcombudsman[6]", "Download brochures for more info: Long-Term Care Ombudsman Brochure or Resident Rights Brochure[6]", "In-person: Contact assigned Local Ombudsman at the facility[5]"],
    "processing_time": "Timely response required; local ombudsmen organized for effective completion, but no fixed timeline specified—depends on complaint urgency[1]",
    "waitlist": null,
    "forms": ["No specific application form for receiving services; informal complaint/contact process (not a volunteer application)[1][6]"],
    "documents": ["No documents required; families/residents can contact directly with concerns—no formal proof of eligibility needed[1][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to long-term care facilities and specified HCBS waiver programs across Iowa[1][5][6]",
    "regional_variations": "Program operates through Local Ombudsmen assigned to each facility; each local office accountable for its geographic area, potentially varying in response organization/timeliness, but uniform standards apply statewide[1][5]",
    "offices_or_providers": ["Local Long-Term Care Ombudsmen assigned to every nursing home, assisted living, residential care facility, elder group home in Iowa; statewide Office of the State Long-Term Care Ombudsman within Iowa Department of Health and Human Services[1][5][6]"]
  },
  "official_source": "https://hhs.iowa.gov/health-prevention/aging-services/ltcombudsman",
  "gotchas": ["Not a healthcare or financial aid program—purely advocacy for rights/complaints, not direct services like care or funding[6]", "Families considering placement or with loved ones in facilities can contact preemptively, but core service is for current residents[3]", "Volunteers (not recipients) have age 18+ requirement, criminal background check, conflict of interest rules, transportation needs—confused with service eligibility[2][3][4]", "Exclusions apply to certain residential care levels (e.g., acute mental health needs)—check facility type[1][6]", "Must contact Local Ombudsman posted in facility, not assume statewide office handles all[5]"],
  "data_shape_notes": "no income test; open to all long-term care residents statewide via local ombudsmen at every facility; advocacy-only, no quantified benefits like hours/dollars; serves HCBS waiver members beyond facilities"
}
